import { render, screen } from '@testing-library/react';
import { describe, it, expect, vi } from 'vitest';
import Home from '../app/page';

// Mock fetch
global.fetch = vi.fn((url) => {
    if (url === '/api/categories') {
        return Promise.resolve({
            json: () => Promise.resolve({ categories: [{ id: 1, name: 'Politics', slug: 'politics' }] })
        });
    }
    if (url.toString().startsWith('/api/news')) {
        return Promise.resolve({
            json: () => Promise.resolve({ articles: [] })
        });
    }
    return Promise.resolve({ json: () => Promise.resolve({}) });
}) as any;

describe('Home Page', () => {
    it('renders the header correctly', async () => {
        render(<Home />);

        // Header text
        expect(screen.getByText("Today's Headlines")).toBeTruthy();
        expect(screen.getByText("Discover the most important stories happening right now, curated specially for you.")).toBeTruthy();

        // Initial loading state
        expect(screen.getByText("Loading articles...")).toBeTruthy();

        // Wait for the articles to load (mock resolves immediately)
        await screen.findByText('No articles found');
    });
});

'use client';

import { useEffect, useState } from 'react';
import { ArticleCard } from '@/components/news/ArticleCard';
import { Badge } from '@/components/ui/badge';

export default function Home() {
  const [articles, setArticles] = useState<any[]>([]);
  const [categories, setCategories] = useState<any[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch categories
    fetch('/api/categories')
      .then(res => res.json())
      .then(data => setCategories(data.categories || []))
      .catch(err => console.error('Failed to load categories', err));
  }, []);

  useEffect(() => {
    // Fetch articles (all or filtered)
    setLoading(true);
    const url = selectedCategory
      ? `/api/news?category=${selectedCategory}`
      : '/api/news';

    fetch(url)
      .then(res => res.json())
      .then(data => {
        setArticles(data.articles || []);
        setLoading(false);
      })
      .catch(err => {
        console.error('Failed to load articles', err);
        setLoading(false);
      });
  }, [selectedCategory]);

  return (
    <main className="container mx-auto px-4 py-8 max-w-screen-2xl">
      <header className="mb-10 text-center md:text-left">
        <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight mb-4 bg-clip-text text-transparent bg-gradient-to-r from-primary to-primary/50">
          Today's Headlines
        </h1>
        <p className="text-muted-foreground text-lg max-w-2xl">
          Discover the most important stories happening right now, curated specially for you.
        </p>
      </header>

      {/* Categories Filter */}
      <div className="flex flex-wrap gap-2 mb-8">
        <Badge
          variant={selectedCategory === null ? 'default' : 'outline'}
          className="cursor-pointer text-sm px-4 py-1"
          onClick={() => setSelectedCategory(null)}
        >
          All News
        </Badge>
        {categories.map(cat => (
          <Badge
            key={cat.id}
            variant={selectedCategory === cat.slug ? 'default' : 'outline'}
            className="cursor-pointer text-sm px-4 py-1"
            onClick={() => setSelectedCategory(cat.slug)}
          >
            {cat.name}
          </Badge>
        ))}
      </div>

      {/* Articles Grid */}
      {loading ? (
        <div className="text-center py-20 text-muted-foreground">Loading articles...</div>
      ) : articles.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {articles.map(article => (
            <ArticleCard key={article.id} article={article} />
          ))}
        </div>
      ) : (
        <div className="text-center py-20 bg-muted/30 rounded-lg border border-dashed">
          <h3 className="text-xl font-medium mb-2">No articles found</h3>
          <p className="text-muted-foreground">There are no articles available in this category.</p>
        </div>
      )}
    </main>
  );
}

import { Card, CardContent, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';

interface ArticleProps {
    article: {
        id: number;
        title: string;
        slug: string;
        content: string;
        snippet: string;
        imageUrl: string | null;
        publishedAt: string;
        author: string | null;
        source: string | null;
        category?: {
            id: number;
            name: string;
            slug: string;
        } | null;
    };
}

export function ArticleCard({ article }: ArticleProps) {
    const date = new Date(article.publishedAt).toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric',
        year: 'numeric'
    });

    return (
        <Card className="overflow-hidden flex flex-col transition-all hover:shadow-md border-border/50 bg-card/50 backdrop-blur-sm group" id={`article-${article.id}`}>
            {article.imageUrl && (
                <div className="relative h-48 w-full overflow-hidden">
                    <img
                        src={article.imageUrl}
                        alt={article.title}
                        className="object-cover w-full h-full transition-transform duration-500 group-hover:scale-105"
                    />
                </div>
            )}
            <CardHeader className="p-4 pb-2">
                <div className="flex items-center justify-between mb-2">
                    {article.category && (
                        <Badge variant="secondary" className="text-xs cursor-pointer hover:bg-secondary/80">
                            {article.category.name}
                        </Badge>
                    )}
                    <span className="text-xs text-muted-foreground font-medium">{date}</span>
                </div>
                <CardTitle className="text-lg leading-tight line-clamp-2 cursor-pointer hover:text-primary transition-colors">
                    {article.title}
                </CardTitle>
            </CardHeader>
            <CardContent className="p-4 pt-0 flex-1">
                <p className="text-sm text-muted-foreground line-clamp-3 leading-relaxed">
                    {article.snippet}
                </p>
            </CardContent>
            <CardFooter className="p-4 pt-0 flex items-center justify-between mt-auto">
                <div className="flex items-center gap-2">
                    <div className="text-xs font-semibold">{article.source || article.author || 'NewsHub'}</div>
                </div>
                <button className="text-xs font-medium text-primary hover:underline underline-offset-4">
                    Read more
                </button>
            </CardFooter>
        </Card>
    );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { Input } from '@/components/ui/input';
import { Search } from 'lucide-react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';

export function SearchBar() {
    const [query, setQuery] = useState('');
    const [results, setResults] = useState<any[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const wrapperRef = useRef<HTMLDivElement>(null);
    const router = useRouter();

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        const fetchResults = async () => {
            if (!query.trim()) {
                setResults([]);
                return;
            }
            setIsSearching(true);
            try {
                const res = await fetch(`/api/search?q=${encodeURIComponent(query)}`);
                const data = await res.json();
                setResults(data.articles || []);
            } catch (error) {
                console.error(error);
            } finally {
                setIsSearching(false);
            }
        };

        const debounce = setTimeout(fetchResults, 300);
        return () => clearTimeout(debounce);
    }, [query]);

    return (
        <div ref={wrapperRef} className="relative w-full max-w-sm">
            <div className="relative">
                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                    type="search"
                    placeholder="Search news..."
                    className="pl-8 bg-muted/50 focus-visible:ring-1 transition-all"
                    value={query}
                    onChange={(e) => {
                        setQuery(e.target.value);
                        setIsOpen(true);
                    }}
                    onFocus={() => {
                        if (query) setIsOpen(true);
                    }}
                />
            </div>

            {isOpen && query && (
                <div className="absolute top-12 left-0 w-full bg-background border rounded-md shadow-lg overflow-hidden z-50">
                    {isSearching ? (
                        <div className="p-4 text-sm text-center text-muted-foreground">Searching...</div>
                    ) : results.length > 0 ? (
                        <ul className="max-h-[300px] overflow-auto">
                            {results.map((article) => (
                                <li key={article.id} className="border-b last:border-0 hover:bg-muted/50 transition-colors">
                                    <Link
                                        href={`#article-${article.id}`}
                                        className="block p-3"
                                        onClick={() => setIsOpen(false)}
                                    >
                                        <div className="font-medium text-sm line-clamp-1">{article.title}</div>
                                        <div className="text-xs text-muted-foreground line-clamp-1 mt-1">{article.snippet}</div>
                                    </Link>
                                </li>
                            ))}
                        </ul>
                    ) : (
                        <div className="p-4 text-sm text-center text-muted-foreground">No results found for "{query}"</div>
                    )}
                </div>
            )}
        </div>
    );
}

import { db } from '../db';
import { articles, categories } from '../db/schema';
import { eq, desc, like, or } from 'drizzle-orm';
import Fuse from 'fuse.js';

export async function getCategories() {
    return await db.select().from(categories).all();
}

export async function getLatestArticles(limit = 10, categorySlug?: string | null) {
    let query = db
        .select({
            id: articles.id,
            title: articles.title,
            slug: articles.slug,
            content: articles.content,
            snippet: articles.snippet,
            imageUrl: articles.imageUrl,
            publishedAt: articles.publishedAt,
            author: articles.author,
            source: articles.source,
            category: categories,
        })
        .from(articles)
        .leftJoin(categories, eq(articles.categoryId, categories.id));

    if (categorySlug) {
        // get category
        const cat = await db.select().from(categories).where(eq(categories.slug, categorySlug)).get();
        if (cat) {
            // It's a bit tricky to chain conditionally in drizzle without dynamic query building, 
            // but we can just use where
            query = db
                .select({
                    id: articles.id,
                    title: articles.title,
                    slug: articles.slug,
                    content: articles.content,
                    snippet: articles.snippet,
                    imageUrl: articles.imageUrl,
                    publishedAt: articles.publishedAt,
                    author: articles.author,
                    source: articles.source,
                    category: categories,
                })
                .from(articles)
                .leftJoin(categories, eq(articles.categoryId, categories.id))
                .where(eq(articles.categoryId, cat.id));
        }
    }

    return await query.orderBy(desc(articles.publishedAt)).limit(limit).all();
}

export async function searchArticlesFuzzy(searchQuery: string) {
    // A real scale app would use a dedicated search engine or Full Text Search in DB
    // For this, we fetch all articles (or a large limit) and use Fuse.js
    const allArticles = await db
        .select({
            id: articles.id,
            title: articles.title,
            slug: articles.slug,
            content: articles.content,
            snippet: articles.snippet,
            imageUrl: articles.imageUrl,
            publishedAt: articles.publishedAt,
            author: articles.author,
            source: articles.source,
            category: categories,
        })
        .from(articles)
        .leftJoin(categories, eq(articles.categoryId, categories.id))
        .all();

    const fuse = new Fuse(allArticles, {
        keys: ['title', 'snippet', 'content', 'category.name'],
        includeScore: true,
        threshold: 0.4 // Adjust threshold for fuzziness
    });

    const exactMatches = fuse.search(searchQuery);
    return exactMatches.map(m => m.item);
}

import { expect, afterEach } from 'vitest';
import { cleanup } from '@testing-library/react';

afterEach(() => {
    cleanup();
});
